154	  opacity: 0;
155	}
156	.particle.active {
157	  animation: particleFloat 2s infinite;
158	}
159	.particle:nth-child(1) { left: 20%; animation-delay: 0s; }
160	.particle:nth-child(2) { left: 40%; animation-delay: 0.4s; }
161	.particle:nth-child(3) { left: 60%; animation-delay: 0.8s; }
162	.particle:nth-child(4) { left: 80%; animation-delay: 1.2s; }
163	
164	@keyframes particleFloat {
165	  0% { bottom: 0; opacity: 0; }
166	  20% { opacity: 0.8; }
167	  100% { bottom: 100%; opacity: 0; }
168	}
169	
170	/* SVG lines */
171	#lines-svg {
172	  position: absolute;
173	  inset: 0;
174	  width: 100%;
175	  height: 100%;
176	  pointer-events: none;
177	  z-index: 0;
178	}
179	.report-line {
180	  stroke: #4a5568;
181	  stroke-width: 1.5;
182	  stroke-dasharray: 6 4;
183	  transition: stroke 0.5s;
184	}
185	.report-line.active {
186	  stroke: #f6c23e;
187	  stroke-dasharray: 8 4;
188	  animation: dashMove 1s linear infinite;
189	}
190	
191	@keyframes dashMove {
192	  to { stroke-dashoffset: -24; }
193	}
194	
195	/* Walking agent */
196	.walking-agent {
197	  position: absolute;
198	  font-size: 20px;
199	  z-index: 20;
200	  transition: left 0.8s ease-in-out, top 0.8s ease-in-out;
201	  pointer-events: none;
202	}
203	.walking-agent.moving {
204	  animation: walkBounce 0.3s infinite;
205	}
206	
207	@keyframes walkBounce {
208	  0%, 100% { transform: translateY(0); }
209	  50% { transform: translateY(-6px); }
210	}
211	
212	/* Project banner */
213	#project-banner {
214	  position: absolute;
215	  top: 8px;
216	  right: 16px;
217	  background: #1a1d2e;
218	  border: 1px solid #2d3748;
219	  border-radius: 8px;
220	  padding: 6px 14px;
221	  font-size: 11px;
222	  color: #8892b0;
223	  z-index: 30;
224	}
225	#project-banner .active-project {
226	  color: #f6c23e;
227	  font-weight: 600;
228	}
229	
230	/* Members area in department office */
231	.members-row {
232	  display: flex;
233	  gap: 2px;
234	  font-size: 11px;
235	}
236	</style>
237	</head>
238	<body>
239	
240	<div id="viz-container">
241	  <svg id="lines-svg"></svg>
242	  <div id="project-banner">
243	    <span id="proj-status">🏢 一人公司</span>
244	    <span id="proj-name" style="display:none"> — <span class="active-project"></span></span>
245	  </div>
246	</div>
247	
248	<script>
249	// Data will be injected by Python
250	// __VIZ_DATA_PLACEHOLDER__
251	
252	const container = document.getElementById('viz-container');
253	const linesSvg = document.getElementById('lines-svg');
254	
255	let offices = [];
256	let walkingAgent = null;
257	
258	function init() {
259	  const data = typeof VIZ_DATA !== 'undefined' ? VIZ_DATA : { offices: [], reports: [], project: {} };
260	
261	  // Update project banner
262	  if (data.project && data.project.name) {
263	    document.getElementById('proj-status').textContent = {pending:'⏳', in_progress:'🔄', review:'👁', done:'✅'}[data.project.status] || '🏢';
264	    document.getElementById('proj-name').style.display = 'inline';
265	    document.getElementById('proj-name').querySelector('.active-project').textContent = data.project.name;
266	  }
267	
268	  const w = container.clientWidth;
269	  const h = container.clientHeight;
270	
271	  // Draw reporting lines
272	  drawLines(data.reports || [], w, h);
273	
274	  // Create offices
275	  data.offices?.forEach(o => createOffice(o, w, h));
276	
277	  // Random thought bubble rotation
278	  setInterval(cycleThoughts, 4000);
279	  cycleThoughts();
280	
281	  // Simulation tick
282	  setInterval(simulationTick, 800);
283	}
284	
285	function createOffice(data, cw, ch) {
286	  const x = (data.position?.x || 50) / 100 * cw;
287	  const y = (data.position?.y || 50) / 100 * ch;
288	
289	  const el = document.createElement('div');
290	  el.className = 'office';
291	  el.id = `office-${data.id}`;
292	  el.style.left = x + 'px';
293	  el.style.top = y + 'px';
294	  el.dataset.type = data.type;
295	  el.dataset.thought = data.thought || '';
296	
297	  el.innerHTML = `
298	    <div class="thought-bubble"></div>
299	    <div class="office-building ${data.type}">
300	      <div class="status-dot ${data.status || 'idle'}"></div>
301	      <div class="office-avatar">${data.avatar || '🤖'}</div>
302	      <div class="office-name">${data.name || '?'}</div>
303	      <div class="office-label">${data.label || ''}</div>
304	      ${data.members ? `<div class="members-row">${data.members.map(m => m.avatar || '🧑‍💻').join('')}</div>` : ''}
305	      <div class="working-particles">
306	        <div class="particle ${data.status === 'working' ? 'active' : ''}"></div>
307	        <div class="particle ${data.status === 'working' ? 'active' : ''}"></div>
308	        <div class="particle ${data.status === 'working' ? 'active' : ''}"></div>
309	        <div class="particle ${data.status === 'working' ? 'active' : ''}"></div>
310	      </div>
311	    </div>
312	  `;
313	
314	  container.appendChild(el);
315	  offices.push({ id: data.id, el, x, y, type: data.type, status: data.status, avatar: data.avatar });
316	}
317	
318	function drawLines(reports, w, h) {
319	  let svgInner = '';
320	  reports.forEach(r => {
321	    const fromEl = document.getElementById(`office-${r.from}`);
322	    const toEl = document.getElementById(`office-${r.to}`);
323	    if (fromEl && toEl) {
324	      const x1 = parseFloat(fromEl.style.left);
325	      const y1 = parseFloat(fromEl.style.top);
326	      const x2 = parseFloat(toEl.style.left);
327	      const y2 = parseFloat(toEl.style.top);
328	      svgInner += `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" class="report-line ${r.active ? 'active' : ''}"/>`;
329	    }
330	  });
331	  linesSvg.innerHTML = svgInner;
332	}
333	
334	function cycleThoughts() {
335	  offices.forEach((o, i) => {
336	    const bubble = o.el.querySelector('.thought-bubble');
337	    const thought = o.el.dataset.thought;
338	    if (bubble && thought) {
339	      bubble.textContent = thought;
340	      bubble.classList.add('visible');
341	      setTimeout(() => bubble.classList.remove('visible'), 2500);
342	    }
343	  });
344	}
345	
346	function simulationTick() {
347	  const activeOffice = offices.find(o => o.status === 'reporting');
348	  if (activeOffice && !walkingAgent) {
349	    // Animate walking from department to CEO
350	    const ceoOffice = offices.find(o => o.type === 'ceo');
351	    if (ceoOffice) {
352	      walkBetween(activeOffice, ceoOffice, () => {
353	        // Then CEO walks to chairman
354	        const chairmanOffice = offices.find(o => o.type === 'chairman');
355	        if (chairmanOffice) {
356	          setTimeout(() => walkBetween(ceoOffice, chairmanOffice, null), 1000);
357	        }
358	      });
359	    }
360	  }
361	}
362	
363	function walkBetween(from, to, callback) {
364	  walkingAgent = document.createElement('div');
365	  walkingAgent.className = 'walking-agent moving';
366	  walkingAgent.textContent = from.avatar || '🤖';
367	  walkingAgent.style.left = from.el.style.left;
368	  walkingAgent.style.top = from.el.style.top;
369	  container.appendChild(walkingAgent);
370	
371	  requestAnimationFrame(() => {
372	    walkingAgent.style.left = to.el.style.left;
373	    walkingAgent.style.top = to.el.style.top;
374	  });
375	
376	  setTimeout(() => {
377	    if (walkingAgent) {
378	      walkingAgent.remove();
379	      walkingAgent = null;
380	    }
381	    if (callback) callback();
382	  }, 900);
383	}
384	
385	// Initialize
386	window.addEventListener('DOMContentLoaded', init);
387	window.addEventListener('resize', () => {
388	  offices = [];
389	  container.querySelectorAll('.office').forEach(el => el.remove());
390	  init();
391	});
392	</script>
393	</body>
394	</html>
